// DB read replica routing in Spring
@Bean
@Primary
public DataSource routingDataSource(
        @Qualifier("primary") DataSource primary,
        @Qualifier("replica") DataSource replica) {
    return new ReadWriteRoutingDataSource(primary, replica);
    // Routes @Transactional(readOnly=true) to replica automatically
}

// Cache-aside with Spring Cache + Redis
@Service
public class ProductService {

    @Cacheable(value = "products", key = "#id",
               unless = "#result == null")
    public Product findById(long id) {
        return productRepo.findById(id).orElse(null); // cache miss: DB call
    }

    @CacheEvict(value = "products", key = "#product.id")
    public Product update(Product product) {
        return productRepo.save(product); // evict stale cached entry
    }

    @CachePut(value = "products", key = "#result.id")
    public Product create(Product product) {
        return productRepo.save(product); // populate cache on create
    }
}

