// Spring Kafka producer
@Service
public class OrderEventPublisher {
    private final KafkaTemplate<String, OrderEvent> kafka;

    public void publish(OrderEvent event) {
        kafka.send("orders", event.orderId(), event)  // key=orderId ensures ordering
             .addCallback(
                 result  -> log.info("Published offset {}", result.getRecordMetadata().offset()),
                 failure -> log.error("Publish failed", failure)
             );
    }
}

// Spring Kafka consumer
@Component
public class InventoryConsumer {
    @KafkaListener(topics = "orders",
                   groupId = "inventory-service",
                   concurrency = "3")  // 3 consumer threads
    public void onOrder(OrderEvent event,
                        Acknowledgment ack) {
        try {
            inventoryService.reserve(event);
            ack.acknowledge();     // manual commit after successful processing
        } catch (Exception e) {
            // Don't ack — message will be redelivered (at-least-once)
            log.error("Failed to process order {}", event.orderId(), e);
        }
    }
}

// Idempotency key in consumer — handle duplicate delivery
public void reserve(OrderEvent event) {
    if (processedIds.contains(event.orderId())) return; // already processed
    // ... process ...
    processedIds.add(event.orderId());
}

// Base62 encoding
private static final String CHARS = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";

String encode(long id) {
    StringBuilder sb = new StringBuilder();
    while (id > 0) {
        sb.append(CHARS.charAt((int)(id % 62)));
        id /= 62;
    }
    return sb.reverse().toString();
}

long decode(String code) {
    long id = 0;
    for (char c : code.toCharArray())
        id = id * 62 + CHARS.indexOf(c);
    return id;
}

// Redirect endpoint with cache
@GetMapping("/{code}")
public ResponseEntity<Void> redirect(@PathVariable String code) {
    String url = cache.get(code); // Redis first
    if (url == null) {
        url = urlRepo.findByCode(code)
                     .orElseThrow(() -> new ResponseStatusException(NOT_FOUND))
                     .getOriginalUrl();
        cache.set(code, url, Duration.ofHours(24));
    }
    return ResponseEntity.status(HttpStatus.FOUND)  // 302
                         .location(URI.create(url))
                         .build();
}

// Capacity estimation:
// 100M URLs × ~500 bytes = 50 GB storage (manageable)
// 1000 reads/s × 1KB response = 1 MB/s bandwidth
// Cache 20% of URLs covers 80% of traffic (Pareto)

// Token bucket with Redis (atomic Lua script)
// KEYS[1] = rate:userId, ARGV[1] = window seconds, ARGV[2] = limit
String lua = """
    local tokens = redis.call('GET', KEYS[1])
    if tokens == false then
        redis.call('SET', KEYS[1], ARGV[2] - 1)
        redis.call('EXPIRE', KEYS[1], ARGV[1])
        return 1  -- allowed
    end
    if tonumber(tokens) <= 0 then
        return 0  -- rejected
    end
    redis.call('DECR', KEYS[1])
    return 1  -- allowed
    """;

Boolean allowed = (Boolean) redis.execute(
    new DefaultRedisScript<>(lua, Boolean.class),
    List.of("rate:" + userId), "60", "100"
);

if (!Boolean.TRUE.equals(allowed)) {
    response.setHeader("Retry-After", "60");
    response.sendError(429, "Too Many Requests");
    return;
}

// Spring filter for rate limiting
@Component
public class RateLimitFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest req,
                                    HttpServletResponse res,
                                    FilterChain chain) throws IOException, ServletException {
        String userId = extractUserId(req);
        if (!rateLimiter.isAllowed(userId)) {
            res.setStatus(429);
            res.setHeader("Retry-After", "60");
            return;
        }
        chain.doFilter(req, res);
    }
}

// Notification request → Kafka fan-out
@Service
public class NotificationService {

    public void notify(NotificationRequest req) {
        // Look up user preferences
        UserPrefs prefs = prefsRepo.findByUserId(req.userId());

        // Fan out to enabled channels
        if (prefs.isPushEnabled())
            kafka.send("notifications.push",
                new PushNotification(req, prefs.getDeviceToken()));
        if (prefs.isEmailEnabled())
            kafka.send("notifications.email",
                new EmailNotification(req, prefs.getEmail()));
        if (prefs.isSmsEnabled())
            kafka.send("notifications.sms",
                new SmsNotification(req, prefs.getPhone()));
    }
}

// Push worker — idempotent delivery
@KafkaListener(topics = "notifications.push", groupId = "push-worker")
public void sendPush(PushNotification notif, Acknowledgment ack) {
    // Check deduplication store before sending
    if (sentNotifications.contains(notif.idempotencyKey())) {
        ack.acknowledge(); return; // already sent
    }
    try {
        fcm.send(notif.deviceToken(), notif.title(), notif.body());
        sentNotifications.add(notif.idempotencyKey(), Duration.ofDays(7));
        ack.acknowledge();
    } catch (FcmException e) {
        log.error("Push failed for user {}", notif.userId(), e);
        // Don't ack — Kafka will redeliver
    }
}
